#include<bits/stdc++.h>
using namespace std;





string smallestWindow(string& s, string& t){
    int n = s.length();
    int m = t.length();

    if(m > n) return "";

    unordered_map<char,int> mp;
    for(char &ch : t){
        mp[ch]++;
    }

    int requiredCount = m;
    int minWindow = INT_MAX;
    int i = 0, j = 0;
    int start = -1;

    while(j < n){
        char ch = s[j];
        if(mp[ch] > 0){
            requiredCount--;
        }

        mp[ch]--;

        while(requiredCount == 0){
            if(minWindow > j - i + 1){
                minWindow = j - i + 1;
                start = i;
            }
            mp[s[i]]++;
            if(mp[s[i]] > 0){
                requiredCount++;
            }
            i++;
        }
        j++;
    }
    return start == -1 ? "" : s.substr(start, minWindow);
}

int main(){
    string s, p;
    cin>>s>>p;
    cout<<smallestWindow(s , p);
    return 0;
}

