int minCost(int n, vector<int>& arr){

    priority_queue<int, vector<int>,  greater<int>> min_heap;
    for(auto x : arr){
        min_heap.push(x);
    }

    int cost = 0;
    while (min_heap.size() > 1)
    {
        int first = min_heap.top();
        min_heap.pop();

        int second = 0;
        if(!min_heap.empty()){
            second = min_heap.top();
            min_heap.pop();
        }

        cost += first + second;
        min_heap.push(first + second);
    }

    return cost;    
}

