string decodeString(string& s){

    stack<char> st;

    for(auto ch : s){
        if(ch == ']'){
            string new_str  = "";
            string num;
            while (!st.empty() && st.top() != '[')
            {
                new_str = st.top() + new_str;
                st.pop();
            }

            st.pop();

            while(!st.empty() && isdigit(st.top())){
                num = st.top() + num;
                st.pop();
            }

            int n = stoi(num);
            string temp = new_str;

            for(int i=1; i<n; i++){
                new_str += temp;
            }

            for(auto c : new_str){
                st.push(c);
            }

        }else{
            st.push(ch);
        }
    }

    string res;

    while(!st.empty()){
        res = st.top() + res;
        st.pop();
    }

    return res;
}

int main(){
