int maxValue(int n, int C, vector<int>& v, vector<int>& w){
    vector<vector<int>> dp(n+1, vector<int> (C+1,0));

    for(int i = 0; i <= n; i++){
        for(int j = 0; j <= C; j++){
            if(i == 0 || j == 0){
                dp[i][j] = 0;
            }else{
                int pick = 0;
                if(w[i-1] <= j){
                    pick = v[i-1] + dp[i-1][j-w[i-1]]; 
                }
                int not_pick = dp[i-1][j];

                dp[i][j] = max(pick,not_pick);
            }
        }
    }

    return dp[n][C];
}

