}

int sumAbsent(int N, vector<int>& S){
    int mod = 1e9+7;
    if(N == 0) return 1;

    sort(S.begin(), S.end());

    vector<int> subset;
    vector<vector<int>> res;
    findSubsets(0, S, subset, res);

    int ans = 0;
    for(const auto &v : res){
        int min_val = 1;
        for(const auto &x : v){
            if(x == min_val) min_val++;
        }
        ans = (ans + min_val) % mod;
    }

    return ans % mod;
}

