const long long MOD = 1e9 + 7;

long long C[1001][1001]; // adjust size as needed

void precompute(int n) {
    C[0][0] = 1;
    for (int i = 1; i <= n; i++) {
        C[i][0] = 1;
        for (int j = 1; j <= i; j++)
            C[i][j] = (C[i-1][j-1] + C[i-1][j]) % MOD;
    }
}

int main() {
