    cin >> n >> x;
    vector<int> s(n);
    for (int& v : s) cin >> v;

    precompute(n);

    long long ans = 0;

    int start = x % 2; // k starts at 0 if X even, 1 if X odd
    int limit = min(x, n);

    for (int k = start; k <= limit; k += 2) {
        ans = (ans + C[n][k]) % MOD;
    }

    cout << ans << endl;
    return 0;
}

