int TotalSunday(string day, int n){
    unordered_map<string,int> days;
    days.insert({"sun",0});
    days.insert({"mon",6});
    days.insert({"tue",5});
    days.insert({"wed",4});
    days.insert({"thu",3});
    days.insert({"fri",2});
    days.insert({"sat",1});

    int count = 0;
    int rem_days = n - days[day];

    if(rem_days >= 0){
        count = 1 + (rem_days / 7);
    }
    return count;

}

int main(){
    string day;
    cin>>day;
    int no_of_days;
    cin>>no_of_days;

    cout<<TotalSunday(day,no_of_days);
    return 0;
}

