int main(){
    int n;
    cin>>n;
    vector<int> arr(n);

    for(int i=0; i<n; i++){
        cin>>arr[i];
    }

    int l = 0, m = 0, h = n-1;
    while(m <= h){
        if(arr[m] == 0){
            swap(arr[l++],arr[m++]);
        }else if(arr[m] == 1){
            m++;
        }else{
            swap(arr[m],arr[h--]);
        }
    }

    for(int x : arr){
        cout<<x<<" ";
    }
    return 0;
}

