int Find(string S, int L){
    int n = S.size();
    int max_count = 0;
    int curr_count = 0;

    for(int i=0; i<n; i++){

        if(i % L == 0){
            max_count = max(curr_count,max_count);
            curr_count = 0;
        }

        if(S[i] == 'a'){
            curr_count++;
        }

    }
    return max_count = max(curr_count,max_count);

}

int main(){
    string str;
    cin>>str;
    int L;
    cin>>L;

    cout<<Find(str,L);
    return 0;
}

