int findPower(int a, int b){
    if(b == 0) return 1;
    int half = findPower(a , b / 2);
    int res = half * half;
    if(b & 1){
        res *= a;
    }
    return res;
}

int main(){
    int num;
    cin>>num;

    int power;
    cin>>power;

    cout<<findPower(num,power);

    return 0;
}

#include<bits/stdc++.h>
using namespace std;

bool compare(vector<int>& a, vector<int>& b){
    double x = (1.0 * a[0]) / a[1];
    double y = (1.0 * b[0]) / b[1];
    return x > y;
}

int fractionalKnapsack(vector<int>& val, vector<int>& wt, int W){
    int n = val.size();
    vector<vector<int>> items(n,vector<int>(2));

    for(int i = 0; i < n; i++){
        items[i][0] = val[i];
        items[i][1] = wt[i];
    }

    sort(begin(items), end(items), compare);

    double res = 0.0;
    for(int i = 0; i < n; i++){
        if(items[i][1] <= W){
            res += items[i][0];
            W -= items[i][1];
        }else{
            res += (1.0 * items[i][0] / items[i][1]) * W;
            break;
        }
    }
    return res;
}

int main(){
    vector<int> val = {10,20,30};
    vector<int> wt = {1,2,3};
    int capacity = 6;

    cout<<fractionalKnapsack(val,wt,capacity);
    return 0;
}
